void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

void show_progress_done(void) { flushed_printf("\n"); }

template <typename T>
struct Ops {
  __device__ __forceinline__ static T add(T a, T b) { return a + b; }
  __device__ __forceinline__ static T mul(T a, T b) { return a * b; }
  __device__ __forceinline__ static T zero() { return (T)0; }
  __device__ __forceinline__ static T minus_one() { return (T)-1; }
  __device__ __forceinline__ static bool eq(T a, T b) { return a == b; }
};

template <>
struct Ops<__half2> {
  __device__ __forceinline__ static __half2 add(__half2 a, __half2 b) { return __hadd2(a, b); }
  __device__ __forceinline__ static __half2 mul(__half2 a, __half2 b) { return __hmul2(a, b); }
  __device__ __forceinline__ static __half2 zero() {
    __half z = __float2half(0.0f);
    return __halves2half2(z, z);
  }
  __device__ __forceinline__ static __half2 minus_one() {
    __half m = __float2half(-1.0f);
    return __halves2half2(m, m);
  }
  __device__ __forceinline__ static bool eq(__half2 a, __half2 b) {
    return __half2float(__low2half(a)) == __half2float(__low2half(b)) &&
           __half2float(__high2half(a)) == __half2float(__high2half(b));
  }
};

template <typename T, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED>
__global__ void benchmark_func(T seed, T* g_data) {
  const unsigned int blockSize = blockDim.x;
  int stride, idx;

  if (BLOCK_STRIDED) {
    stride = (int)blockSize;
    idx = (int)blockIdx.x * (int)blockSize * ELEMENTS_PER_THREAD + (int)threadIdx.x;
  } else {
    const int grid_size = (int)blockSize * (int)gridDim.x;
    stride = grid_size;
    idx = (int)blockIdx.x * (int)blockSize + (int)threadIdx.x;
  }

  const int big_stride = (int)gridDim.x * (int)blockSize * ELEMENTS_PER_THREAD;

  T tmps[ELEMENTS_PER_THREAD];

#pragma unroll
  for (int k = 0; k < FUSION_DEGREE; k++) {
#pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
#pragma unroll
      for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        tmps[j] = Ops<T>::add(Ops<T>::mul(tmps[j], tmps[j]), seed);
      }
    }

    T sum = Ops<T>::zero();
#pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
      sum = Ops<T>::add(sum, Ops<T>::mul(tmps[j], tmps[j + 1]));
    }

    if (Ops<T>::eq(sum, Ops<T>::minus_one())) g_data[idx + k * big_stride] = sum;
  }
}

#define DISPATCH_CI(CI) \
  case CI: benchmark_func<T, CI, EPT, FD, BS><<<grid, block, 0, stream>>>(seed, ptr); break

template <typename T, bool BS, int EPT, int FD>
static void launch_compute_kernel(int ci, T seed, void* buffer, dim3 grid, dim3 block, cudaStream_t stream = 0) {
  T* ptr = reinterpret_cast<T*>(buffer);
  switch (ci) {
    DISPATCH_CI(0);   DISPATCH_CI(1);   DISPATCH_CI(2);   DISPATCH_CI(3);   DISPATCH_CI(4);
    DISPATCH_CI(5);   DISPATCH_CI(6);   DISPATCH_CI(7);   DISPATCH_CI(8);   DISPATCH_CI(9);
    DISPATCH_CI(10);  DISPATCH_CI(11);  DISPATCH_CI(12);  DISPATCH_CI(13);  DISPATCH_CI(14);
    DISPATCH_CI(15);  DISPATCH_CI(16);  DISPATCH_CI(17);  DISPATCH_CI(18);  DISPATCH_CI(20);
    DISPATCH_CI(22);  DISPATCH_CI(24);  DISPATCH_CI(28);  DISPATCH_CI(32);  DISPATCH_CI(40);
    DISPATCH_CI(48);  DISPATCH_CI(56);  DISPATCH_CI(64);  DISPATCH_CI(80);  DISPATCH_CI(96);
    DISPATCH_CI(128); DISPATCH_CI(192); DISPATCH_CI(256);
    default: break;
  }
}
#undef DISPATCH_CI

template <typename Launcher>
static double timed_launch(bool use_os_timer, Launcher&& launch) {
  if (use_os_timer) {
    auto ts_start = getTimestamp();
    launch();
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
    return getElapsedtime(ts_start);
  } else {
    cudaEvent_t ev_start, ev_stop;
    CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
    CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
    CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
    launch();
    CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
    CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
    float ms = 0.0f;
    CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
    return (double)ms;
  }
}

template <bool BS, int EPT, int FD>
void runbench(unsigned int krn_idx,
              void* cbuffer,
              long size,
              size_t workgroupsize,
              bool use_os_timer,
              bool enable_dp,
              bool enable_hp) {
  const long compute_grid_size = size / EPT / FD;
  const int current_compute_iterations = compute_iterations[krn_idx];
  const long long computations =
      (EPT * (long long)compute_grid_size +
       (2LL * EPT * current_compute_iterations) * (long long)compute_grid_size) *
      FD;
  const long long memoryoperations = size;

  const dim3 block((unsigned int)workgroupsize);
  const dim3 grid((unsigned int)(compute_grid_size / (long)workgroupsize));

  constexpr auto total_bench_iterations = 3;

  double kernel_time_mad_sp = benchmark<total_bench_iterations>([&]() {
    const float seed_f = 1.0f;
    double t = timed_launch(use_os_timer, [&]() {
      launch_compute_kernel<float, BS, EPT, FD>(current_compute_iterations, seed_f, cbuffer, grid, block);
    });
    CUDA_SAFE_CALL(cudaGetLastError());
    return t;
  });

  double kernel_time_mad_dp = benchmark<total_bench_iterations>([&]() {
    if (!enable_dp) return 0.0;
    const double seed_d = 1.0;
    double t = timed_launch(use_os_timer, [&]() {
      launch_compute_kernel<double, BS, EPT, FD>(current_compute_iterations, seed_d, cbuffer, grid, block);
    });
    CUDA_SAFE_CALL(cudaGetLastError());
    return t;
  });

  double kernel_time_mad_hp = benchmark<total_bench_iterations>([&]() {
    if (!enable_hp) return 0.0;
    const __half h = __float2half(1.0f);
    const __half2 seed_h = __halves2half2(h, h);
    double t = timed_launch(use_os_timer, [&]() {
      launch_compute_kernel<__half2, BS, EPT, FD>(current_compute_iterations, seed_h, cbuffer, grid, block);
    });
    CUDA_SAFE_CALL(cudaGetLastError());
    return t;
  });

  double kernel_time_mad_int = benchmark<total_bench_iterations>([&]() {
    const int seed_i = 1;
    double t = timed_launch(use_os_timer, [&]() {
      launch_compute_kernel<int, BS, EPT, FD>(current_compute_iterations, seed_i, cbuffer, grid, block);
    });
    CUDA_SAFE_CALL(cudaGetLastError());
    return t;
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      kernel_time_mad_dp > 0.0 ? ((double)computations) / kernel_time_mad_dp * 1000. /
                                     (double)(1000 * 1000 * 1000)
                               : 0.0,
      kernel_time_mad_dp > 0.0
          ? ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
                (1000. * 1000. * 1000.)
          : 0.0,
      ((double)2 * computations) / ((double)memoryoperations * sizeof(__half2)),
      kernel_time_mad_hp,
      kernel_time_mad_hp > 0.0 ? ((double)2 * computations) / kernel_time_mad_hp * 1000. /
                                     (double)(1000 * 1000 * 1000)
                               : 0.0,
      kernel_time_mad_hp > 0.0
          ? ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp * 1000. /
                (1000. * 1000. * 1000.)
          : 0.0,
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
  constexpr bool block_strided = false;
  constexpr bool host_allocated = false;
  constexpr bool use_os_timer = false;
  constexpr size_t workgroupsize = 256;
  constexpr int elements_per_wi = 8;
  constexpr int fusion_degree = 4;

  printf("Workgroup size:         %zu\n", workgroupsize);
  printf("Elements per workitem:  %d\n", elements_per_wi);
  printf("Workitem fusion degree: %d\n", fusion_degree);

  const char* benchtype = block_strided ? "Workgroup" : "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation = host_allocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n", use_os_timer ? "OS based" : "CL event based");

  int current_device = 0, major = 0, minor = 0;
  CUDA_SAFE_CALL(cudaGetDevice(&current_device));
  CUDA_SAFE_CALL(cudaDeviceGetAttribute(&major, cudaDevAttrComputeCapabilityMajor, current_device));
  CUDA_SAFE_CALL(cudaDeviceGetAttribute(&minor, cudaDevAttrComputeCapabilityMinor, current_device));
  const bool enable_dp = (major > 1) || (major == 1 && minor >= 3);
  if (!enable_dp)
    printf("Warning:                Double precision computations are not supported\n");
  const bool enable_hp = IsFP16Supported();
  if (!enable_hp)
    printf("Warning:                Half precision computations are not supported\n");

  cudaDeviceProp prop;
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&prop, current_device));
  if ((size_t)prop.maxThreadsPerBlock < workgroupsize) {
    fprintf(stderr, "Error: Unsupported workgroup size (%zu).\n", workgroupsize);
    exit(1);
  }

  void* c_buffer = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&c_buffer, (size_t)size * sizeof(double)));
  CUDA_SAFE_CALL(cudaMemset(c_buffer, 0, (size_t)size * sizeof(double)));

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  {
    const dim3 block((unsigned int)workgroupsize);
    const long reduced_grid_size = size / 256;
    const dim3 grid((unsigned int)(reduced_grid_size / (long)workgroupsize));
    benchmark_func<short, 0, 1, 1, block_strided><<<grid, block>>>((short)1, (short*)c_buffer);
    CUDA_SAFE_CALL(cudaGetLastError());
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
  }

  printf(
      "----------------------------------------------------------------------------- CSV data "
      "-----------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision ops,,,,              "
      "Half precision ops,,,,                Integer operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    runbench<block_strided, elements_per_wi, fusion_degree>(
        i, c_buffer, size, workgroupsize, use_os_timer, enable_dp, enable_hp);
  }

  printf(
      "------------------------------------------------------------------------------------------------"
      "--------------------------------------------------------"
      "--------------------\n");

  CUDA_SAFE_CALL(cudaMemcpy(c, c_buffer, (size_t)size * sizeof(double), cudaMemcpyDeviceToHost));
  CUDA_SAFE_CALL(cudaFree(c_buffer));
}
